package ir.tahamohamadi.blog.post;
import ir.tahamohamadi.blog.category.BlogCategory; import ir.tahamohamadi.common.domain.ContentStatus; import ir.tahamohamadi.common.persistence.AuditedSoftDeletableEntity; import ir.tahamohamadi.identity.user.AppUser; import ir.tahamohamadi.media.asset.MediaAsset; import jakarta.persistence.*; import lombok.*; import java.time.Instant; import java.util.*;
@Entity @Table(name="blog_post") @Getter @NoArgsConstructor(access=AccessLevel.PROTECTED) public class BlogPost extends AuditedSoftDeletableEntity { @ManyToOne(fetch=FetchType.LAZY) @JoinColumn(name="author_user_id") private AppUser author; @ManyToOne(fetch=FetchType.LAZY) @JoinColumn(name="category_id",nullable=false) private BlogCategory category; @ManyToOne(fetch=FetchType.LAZY) @JoinColumn(name="cover_media_id") private MediaAsset coverMedia; @Enumerated(EnumType.STRING) @Column(nullable=false,length=20) private ContentStatus status; @Column(name="published_at") private Instant publishedAt; @Column(name="scheduled_for") private Instant scheduledFor; private BlogPost(UUID id,BlogCategory category,Instant at){initialize(id,at);this.category=Objects.requireNonNull(category);status=ContentStatus.DRAFT;} public static BlogPost create(UUID id,BlogCategory category,Instant at){return new BlogPost(id,category,at);} public void updateCategory(BlogCategory category){this.category=Objects.requireNonNull(category);this.updatedAt=Instant.now();} public void publish(Instant at){if(status!=ContentStatus.DRAFT)throw new IllegalStateException("Only draft posts can be published");status=ContentStatus.PUBLISHED;publishedAt=Objects.requireNonNull(at);updatedAt=at;} public void archive(){if(status!=ContentStatus.PUBLISHED)throw new IllegalStateException("Only published posts can be archived");status=ContentStatus.ARCHIVED;updatedAt=Instant.now();} }
